import React, { useEffect, useState } from "react";
import dayjs from "dayjs";

interface CountdownProps {
  targetDate: string;           // es. "2023-03-27T15:00:00"
  onComplete: () => void;
}

const Countdown: React.FC<CountdownProps> = ({ targetDate, onComplete }) => {
  const [timeLeft, setTimeLeft] = useState({
    hours: 0,
    minutes: 0,
    seconds: 0,
  });

  useEffect(() => {
    const target = dayjs(targetDate);

    const updateCountdown = () => {
      const now = dayjs();
      const diffSeconds = target.diff(now, "second");

      if (diffSeconds <= 0) {
        setTimeLeft({ hours: 0, minutes: 0, seconds: 0 });
        onComplete();
        return false;
      }

      const hours = Math.floor(diffSeconds / 3600);
      const minutes = Math.floor((diffSeconds % 3600) / 60);
      const seconds = diffSeconds % 60;

      setTimeLeft({ hours, minutes, seconds });
      return true;
    };

    // Aggiorna subito
    updateCountdown();

    const interval = setInterval(() => {
      const stillRunning = updateCountdown();
      if (!stillRunning) clearInterval(interval);
    }, 1000);

    return () => clearInterval(interval);
  }, [targetDate, onComplete]);

  return (
    <div style={styles.container}>
      <div style={styles.timeBox}>{String(timeLeft.hours).padStart(2, "0")}</div>
      <span style={styles.separator}>:</span>
      <div style={styles.timeBox}>{String(timeLeft.minutes).padStart(2, "0")}</div>
      <span style={styles.separator}>:</span>
      <div style={styles.timeBox}>{String(timeLeft.seconds).padStart(2, "0")}</div>
    </div>
  );
};

// Stili inline semplici
const styles: { [key: string]: React.CSSProperties } = {
  container: {
    display: "flex",
    alignItems: "center",
    fontFamily: "Arial, sans-serif",
    fontSize: "2rem",
    backgroundColor: "#f0f0f0",
    padding: "10px 20px",
    borderRadius: "10px",
    width: "fit-content",
  },
  timeBox: {
    backgroundColor: "#333",
    color: "#fff",
    padding: "10px 15px",
    borderRadius: "5px",
    minWidth: "50px",
    textAlign: "center",
  },
  separator: {
    margin: "0 5px",
  },
};

export default Countdown;